fun solve(nums: Array<Long>): Long {
    val n = nums.size
    var maxVal = 0L

    for (mask in 0L..(1L shl n - 1)) {
        val A = mutableListOf<Long>()
        val B = mutableListOf<Long>()
        val C = mutableListOf<Long>()

        for (i in 0 until n) {
            if ((mask shr i) and 1L) {
                A.add(nums[i])
            } else {
                B.add(nums[i])
            }
        }

        var xorA = 0L
        for (num in A) {
            xorA ^= num
        }

        var xorC = 0L
        for (num in C) {
            xorC ^= num
        }

        var andB = 0L
        for (num in B) {
            andB &= num
        }

        maxVal = maxOf(maxVal, xorA + andB + xorC)
    }

    return maxVal
}
